#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <assert.h>

#include <omp.h>

#define THREADS_PER_DIM 16
#define BLOCKS_PER_DIM 16
#define THREADS_PER_BLOCK THREADS_PER_DIM*THREADS_PER_DIM

#define ASSUMED_NR_CLUSTERS 32

#define CPU_DELTA_REDUCE
#define CPU_CENTER_REDUCE

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

unsigned int num_threads_perdim = THREADS_PER_DIM;
unsigned int num_blocks_perdim = BLOCKS_PER_DIM;
unsigned int num_threads = num_threads_perdim*num_threads_perdim;
unsigned int num_blocks = num_blocks_perdim*num_blocks_perdim;

int    *membership_new;
float  *feature_d;
float  *feature_flipped_d;
int    *membership_d;
float  *block_new_centers;
float  *clusters_d;
float  *block_clusters_d;
int    *block_deltas_d;

float c_clusters[ASSUMED_NR_CLUSTERS*34];

void invert_mapping(float *input,
                    float *output,
                    int npoints,
                    int nfeatures)
{
    int point_id;
    int i;

    #pragma omp parallel for
    for(point_id = 0; point_id < npoints; point_id++){
        for(i=0;i<nfeatures;i++)
            output[point_id + npoints*i] = input[point_id*nfeatures + i];
    }
}

void kmeansPoint(float  *features,
                 int     nfeatures,
                 int     npoints,
                 int     nclusters,
                 int    *membership,
                 float  *clusters,
                 float  *block_clusters,
                 int    *block_deltas)
{
    int point_id;
    int block_id;

    #pragma omp parallel for
    for(block_id = 0; block_id < num_blocks_perdim * num_blocks_perdim; block_id++) {
        int i, j;
        int start_point = block_id * num_threads;
        int end_point = start_point + num_threads;
        if(end_point > npoints) end_point = npoints;

        int local_delta = 0;
        float *local_block_cluster = NULL;
#ifdef BLOCK_CENTER_REDUCE
        local_block_cluster = &block_clusters[block_id * nclusters * nfeatures];
#endif

        for(point_id = start_point; point_id < end_point; point_id++) {
            int index = -1;
            float min_dist = FLT_MAX;
            float dist;

            for (i=0; i<nclusters; i++) {
                int cluster_base_index = i*nfeatures;
                float ans=0.0;

                for (j=0; j < nfeatures; j++) {
                    int addr = point_id + j*npoints;
                    float diff = (features[addr] - c_clusters[cluster_base_index + j]);
                    ans += diff*diff;
                }
                dist = ans;

                if (dist < min_dist) {
                    min_dist = dist;
                    index = i;
                }
            }

            if (point_id < npoints) {
#ifdef GPU_DELTA_REDUCTION
                if (membership[point_id] != index) {
                    local_delta++;
                }
#endif
                membership[point_id] = index;

#ifdef GPU_NEW_CENTER_REDUCTION
                if(local_block_cluster != NULL) {
                    for(int k = 0; k < nfeatures; k++) {
                        int addr = point_id + k*npoints;
                        local_block_cluster[index * nfeatures + k] += features[addr];
                    }
                }
#endif
            }
        }

#ifdef BLOCK_DELTA_REDUCE
        block_deltas[block_id] = local_delta;
#endif
    }
}

extern "C"
int setup(int argc, char** argv);

extern "C"
void allocateMemory(int npoints, int nfeatures, int nclusters, float **features)
{
    num_blocks = npoints / num_threads;
    if (npoints % num_threads > 0)
        num_blocks++;

    num_blocks_perdim = sqrt((double) num_blocks);
    while (num_blocks_perdim * num_blocks_perdim < num_blocks)
        num_blocks_perdim++;

    num_blocks = num_blocks_perdim*num_blocks_perdim;

    membership_new = (int*) malloc(npoints * sizeof(int));
    for(int i=0;i<npoints;i++) {
        membership_new[i] = -1;
    }

    block_new_centers = (float *) malloc(nclusters*nfeatures*sizeof(float));

    feature_flipped_d = (float *) malloc(npoints*nfeatures*sizeof(float));
    memcpy(feature_flipped_d, features[0], npoints*nfeatures*sizeof(float));
    feature_d = (float *) malloc(npoints*nfeatures*sizeof(float));

    invert_mapping(feature_flipped_d, feature_d, npoints, nfeatures);

    membership_d = (int*) malloc(npoints*sizeof(int));
    clusters_d = (float *) malloc(nclusters*nfeatures*sizeof(float));

#ifdef BLOCK_DELTA_REDUCE
    block_deltas_d = (int *) malloc(num_blocks_perdim * num_blocks_perdim * sizeof(int));
#endif

#ifdef BLOCK_CENTER_REDUCE
    block_clusters_d = (float *) malloc(
        num_blocks_perdim * num_blocks_perdim *
        nclusters * nfeatures * sizeof(float));
#endif
}

extern "C"
void deallocateMemory()
{
    free(membership_new);
    free(block_new_centers);
    free(feature_d);
    free(feature_flipped_d);
    free(membership_d);
    free(clusters_d);
#ifdef BLOCK_CENTER_REDUCE
    free(block_clusters_d);
#endif
#ifdef BLOCK_DELTA_REDUCE
    free(block_deltas_d);
#endif
}

int main(int argc, char** argv)
{
    setup(argc, argv);
}

extern "C"
int kmeansCuda(float **feature,
               int nfeatures,
               int npoints,
               int nclusters,
               int *membership,
               float **clusters,
               int *new_centers_len,
               float **new_centers)
{
    int delta = 0;
    int i,j;

    memcpy(membership_d, membership_new, npoints*sizeof(int));
    memcpy(clusters_d, clusters[0], nclusters*nfeatures*sizeof(float));

    memcpy(c_clusters, clusters[0], nclusters*nfeatures*sizeof(float));

    kmeansPoint(feature_d,
                nfeatures,
                npoints,
                nclusters,
                membership_d,
                clusters_d,
                block_clusters_d,
                block_deltas_d);

    memcpy(membership_new, membership_d, npoints*sizeof(int));

#ifdef BLOCK_CENTER_REDUCE
    float *block_clusters_h = (float *) malloc(
        num_blocks_perdim * num_blocks_perdim *
        nclusters * nfeatures * sizeof(float));
    memcpy(block_clusters_h, block_clusters_d,
        num_blocks_perdim * num_blocks_perdim *
        nclusters * nfeatures * sizeof(float));
#endif
#ifdef BLOCK_DELTA_REDUCE
    int *block_deltas_h = (int *) malloc(
        num_blocks_perdim * num_blocks_perdim * sizeof(int));
    memcpy(block_deltas_h, block_deltas_d,
        num_blocks_perdim * num_blocks_perdim * sizeof(int));
#endif

    delta = 0;
    for (i = 0; i < npoints; i++)
    {
        int cluster_id = membership_new[i];
        new_centers_len[cluster_id]++;
        if (membership_new[i] != membership[i])
        {
#ifdef CPU_DELTA_REDUCE
            delta++;
#endif
            membership[i] = membership_new[i];
        }
#ifdef CPU_CENTER_REDUCE
        for (j = 0; j < nfeatures; j++)
        {
            new_centers[cluster_id][j] += feature[i][j];
        }
#endif
    }

#ifdef BLOCK_DELTA_REDUCE
    for(i = 0; i < num_blocks_perdim * num_blocks_perdim; i++) {
        delta += block_deltas_h[i];
    }
#endif
#ifdef BLOCK_CENTER_REDUCE
    for(int j = 0; j < nclusters;j++) {
        for(int k = 0; k < nfeatures;k++) {
            block_new_centers[j*nfeatures + k] = 0.f;
        }
    }

    for(i = 0; i < num_blocks_perdim * num_blocks_perdim; i++) {
        for(int j = 0; j < nclusters;j++) {
            for(int k = 0; k < nfeatures;k++) {
                block_new_centers[j*nfeatures + k] += block_clusters_h[i * nclusters*nfeatures + j * nfeatures + k];
            }
        }
    }

#ifdef BLOCK_CENTER_REDUCE
    for(int j = 0; j < nclusters;j++) {
        for(int k = 0; k < nfeatures;k)
            new_centers[j][k]= block_new_centers[j*nfeatures + k];
    }
#endif
#endif

#ifdef BLOCK_CENTER_REDUCE
    free(block_clusters_h);
#endif
#ifdef BLOCK_DELTA_REDUCE
    free(block_deltas_h);
#endif

    return delta;
}
